ops.replace_with:
if (action === "create_cron_job") {
    const { job_name, schedule, function_slug } = payload;
    const projectUrl = Deno.env.get("SUPABASE_URL");
    const serviceKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
    const fullUrl = `${projectUrl}/functions/v1/${function_slug}`;

    // SQL to enable extensions and schedule the job
    const sql = `
        CREATE EXTENSION IF NOT EXISTS pg_cron;
        CREATE EXTENSION IF NOT EXISTS pg_net;

        SELECT cron.schedule(
            '${job_name}',
            '${schedule}',
            $$
            SELECT net.http_post(
                url:='${fullUrl}',
                headers:='{"Content-Type": "application/json", "Authorization": "Bearer ${serviceKey}"}'::jsonb,
                body:='{"job": "${job_name}", "triggered_at": "' || now() || '"}'::jsonb
            )
            $$
        );
    `.trim();

    // Use the internal SQL executor endpoint
    const sqlRes = await fetch("https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/sql-executor", {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${Deno.env.get("SUPABASE_ANON_KEY")}`,
            'apikey': Deno.env.get("SUPABASE_ANON_KEY")
        },
        body: JSON.stringify({ query: sql })
    });

    const sqlData = await sqlRes.json();
    if (sqlData.error) throw new Error(sqlData.error);

    await supabase.from('conduit_logs').insert({
        repo_name: TARGET_REPO,
        type: 'cron_created',
        data: { job_name, schedule, function_slug, status: "Success" }
    });

    return new Response(JSON.stringify({ success: true, message: `Cron job '${job_name}' scheduled.` }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
}

if (action === "rollback") {

function openCronManager() {
    document.getElementById('cron-manager-overlay').classList.add('active');
    toggleFab(false);

    // Populate function list
    const container = document.getElementById('cron-fn-selector');
    const functions = new Set();
    (window.repoFiles || []).forEach(f => {
        if (f.path.includes('supabase/functions/')) {
            const parts = f.path.split('supabase/functions/')[1].split('/');
            if (parts[0]) functions.add(parts[0]);
        }
    });

    container.innerHTML = Array.from(functions).map(name => `
        <button class="filter-pill" onclick="selectCronFn('${name}', this)">${name}</button>
    `).join('') || '<span style="font-size:10px; color:#444;">No functions found</span>';
}

function closeCronManager() {
    document.getElementById('cron-manager-overlay').classList.remove('active');
    toggleFab(true);
}

function selectCronFn(name, btn) {
    document.querySelectorAll('#cron-fn-selector .filter-pill').forEach(p => p.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById('cron-target-slug').value = name;
    if(!document.getElementById('cron-job-name').value) {
        document.getElementById('cron-job-name').value = 'run-' + name;
    }
}

function setCronPreset(val) {
    document.getElementById('cron-schedule').value = val;
}

async function executeCreateCron() {
    const job_name = document.getElementById('cron-job-name').value.trim();
    const schedule = document.getElementById('cron-schedule').value.trim();
    const function_slug = document.getElementById('cron-target-slug').value.trim();

    if(!job_name || !schedule || !function_slug) return showGlobalToast("Fill all fields", true);

    showGlobalToast("Scheduling...");
    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'create_cron_job', job_name, schedule, function_slug })
        });
        const data = await res.json();
        if(data.success) {
            showGlobalToast("✅ " + data.message);
            closeCronManager();
            fetchState(true);
        } else throw new Error(data.error);
    } catch(e) { showGlobalToast(e.message, true); }
}

async function enableCronExtensions() {
    if(!confirm("Execute SQL to enable pg_cron and pg_net extensions?")) return;
    try {
        const sql = "CREATE EXTENSION IF NOT EXISTS pg_cron; CREATE EXTENSION IF NOT EXISTS pg_net;";
        const res = await fetch("https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/sql-executor", {
            method: 'POST', 
            headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + SQL_CONFIG.ANON, 'apikey': SQL_CONFIG.ANON },
            body: JSON.stringify({ query: sql })
        });
        const data = await res.json();
        if(data.error) throw new Error(data.error);
        showGlobalToast("✅ Extensions Enabled");
    } catch(e) { showGlobalToast(e.message, true); }
}

