                const finalUrl = url.origin + url.pathname + '?' + params.toString();
                e.preventDefault();
                window.parent.postMessage({ type: 'CONDUIT_NAVIGATE', url: finalUrl }, '*');
            }
        }, true);

        console.log("⚡ Conduit Interceptor Active: " + location.href);
