 161 | function textToBase64(str: string) {
 162 |     const bytes = new TextEncoder().encode(str);
 163 |     const binString = Array.from(bytes, (byte) => String.fromCharCode(byte)).join("");
 164 |     return btoa(binString);
 165 | }
