 171 | function isRecordInScope(record: any, scopePath: string): boolean {
 172 |     if (!scopePath || scopePath === "/" || scopePath === "") return true;
 173 |     if (record.type === 'Checkpoint') return true; // Always show checkpoints
 174 |     // Allow if matches scope OR is an Edge Function operation
 175 |     if (record.ops && Array.isArray(record.ops)) {
 176 |         return record.ops.some((op: any) => 
 177 |             (op.file_path && op.file_path.startsWith(scopePath)) || 
 178 |             op.is_resolved_ef ||
 179 |             (op.file_path && op.file_path.includes("supabase/functions/"))
