 323 | async function genericRequestAI(role: keyof AIConfig['roles'], messages: any[], config?: AIConfig, tools?: any[], responseFormat?: any): Promise<any> {
 324 |   const provider = resolveProvider(role, config);
 325 |   if (!provider) throw new Error(`No provider found for role: ${role}`);
 326 | 
 327 |   // AI Trace Summary (Lightweight)
 328 |   console.log(`[AI_CALL] Role: ${role} | Provider: ${provider.name} | Model: ${provider.model}`);
 329 | 
 330 |   // 2. Persistent DB Log
 331 |   // We use a try-catch to ensure logging failure doesn't block the actual AI request
 332 |   try {
 333 |       await supabase.from('conduit_logs').insert({
 334 |           repo_name: 'DEBUG_TRACE', // Utility function doesn't know repo, using placeholder
 335 |           type: 'ai_prompt_dump',
 336 |           data: { 
 337 |               role, 
 338 |               provider: provider.name, 
 339 |               model: provider.model, 
 340 |               timestamp: new Date().toISOString(),
 341 |               messages_preview: messages 
 342 |           }
 343 |       });
 344 |   } catch (e) { console.error("Background log failed:", e); }
 345 |   
 346 |   // Advanced Rotation Logic: Fetch Least-Recently-Used key from 'api_keys' table
 347 |   const serviceMap: Record<string, string> = { 
 348 |       'Deepseek_API': 'deepseek', 
 349 |       'GEMINI_API_KEY': 'gemini', 
 350 |       'GROQ_API_KEY': 'groq' 
 351 |   };
 352 |   const serviceName = serviceMap[provider.apiKeyEnv];
 353 |   let apiKey = "";
 354 | 
 355 |   if (serviceName) {
 356 |       const { data: keyRow } = await supabase
 357 |           .from('api_keys')
 358 |           .select('id, api_key')
 359 |           .eq('service', serviceName)
 360 |           .eq('is_active', true)
 361 |           .or(`cooldown_until.is.null,cooldown_until.lt.${new Date().toISOString()}`)
 362 |           .order('last_used_at', { ascending: true, nullsFirst: true })
 363 |           .limit(1)
 364 |           .maybeSingle();
 365 | 
 366 |       if (keyRow) {
 367 |           apiKey = keyRow.api_key;
 368 |           // Mark as used immediately to move it to the end of the rotation queue
 369 |           await supabase.from('api_keys').update({ last_used_at: new Date().toISOString() }).eq('id', keyRow.id);
 370 |       }
 371 |   }
 372 | 
 373 |   // Fallback to Env Var if no key found in DB or service not mapped
 374 |   if (!apiKey) {
 375 |       apiKey = Deno.env.get(provider.apiKeyEnv) || "";
 376 |       if (!apiKey) {
 377 |           if (provider.apiKeyEnv && provider.apiKeyEnv.length > 10) apiKey = provider.apiKeyEnv;
 378 |           else throw new Error(`Missing API Key: No active keys for '${serviceName || provider.apiKeyEnv}' in DB or Env`);
 379 |       }
 380 |   }
 381 | 
 382 |   // ADAPTER: Google Native
 383 |   if (provider.type === 'google') {
 384 |     const promptText = messages.map(m => `[${m.role.toUpperCase()}]: ${m.content}`).join('\n');
 385 |           const url = `${provider.baseUrl}?key=${apiKey}`;
 386 |     
 387 |     const payload: any = { 
 388 |         contents: [{ parts: [{ text: promptText }] }]
 389 |     };
 390 | 
 391 |     // ADAPTER: Google Strict Function Calling
 392 |     if (tools && tools.length > 0 && messages[0].content.includes('STRICT')) {
 393 |         payload.tool_config = {
 394 |             function_calling_config: {
 395 |                 mode: "ANY",
 396 |                 allowed_function_names: [tools[0].function.name]
 397 |             }
 398 |         };
 399 |     }
 400 | 
 401 |     // MAP OPENAI TOOLS TO GOOGLE FUNCTION DECLARATIONS
 402 |     if (tools && tools.length > 0) {
 403 |         const mapType = (t: any) => {
 404 |             // Flatten union types ["integer", "null"] -> "INTEGER"
 405 |             const rawType = Array.isArray(t) ? t[0] : t;
 406 |             if (rawType === "integer") return "INTEGER";
 407 |             if (rawType === "string") return "STRING";
 408 |             if (rawType === "boolean") return "BOOLEAN";
 409 |             if (rawType === "number") return "NUMBER";
 410 |             if (rawType === "object") return "OBJECT";
 411 |             if (rawType === "array") return "ARRAY";
 412 |             return "STRING"; // Fallback
 413 |         };
 414 | 
 415 |         const transformSchema = (schema: any): any => {
 416 |             const newSchema: any = { type: mapType(schema.type) };
 417 |             if (schema.properties) {
 418 |                 newSchema.properties = {};
 419 |                 for (const key in schema.properties) {
 420 |                     newSchema.properties[key] = transformSchema(schema.properties[key]);
 421 |                 }
 422 |             }
 423 |             if (schema.items) {
 424 |                 newSchema.items = transformSchema(schema.items);
 425 |             }
 426 |             if (schema.required) newSchema.required = schema.required;
 427 |             return newSchema;
 428 |         };
 429 | 
 430 |         payload.tools = [{
 431 |             function_declarations: tools.map((t: any) => ({
 432 |                 name: t.function.name,
 433 |                 description: t.function.description,
 434 |                 parameters: transformSchema(t.function.parameters)
 435 |             }))
 436 |         }];
 437 |     }
 438 |     
 439 |     const res = await fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
 440 |     const data = await res.json();
 441 |     
 442 |     if (data.error) throw new Error(`Google AI Error: ${data.error.message || JSON.stringify(data.error)}`);
 443 |     
 444 |     console.log(`\n=== [AI RESPONSE RECEIVED] Provider: ${provider.name} (Google) ===`);
 445 |     
 446 |     const parts = data.candidates?.[0]?.content?.parts || [];
 447 |     let combinedContent = "";
 448 |     let tool_calls: any[] = [];
 449 | 
 450 |     // Loop through all parts to catch both text and function calls
 451 |     for (const p of parts) {
 452 |         if (p.text) combinedContent += p.text;
 453 |         if (p.functionCall) {
 454 |             tool_calls.push({
 455 |                 function: {
 456 |                     name: p.functionCall.name,
 457 |                     arguments: JSON.stringify(p.functionCall.args)
 458 |                 }
 459 |             });
 460 |         }
 461 |     }
 462 | 
 463 |     return { 
 464 |       raw: data, 
 465 |       content: combinedContent,
 466 |       tool_calls: tool_calls.length > 0 ? tool_calls : undefined
 467 |     };
 468 |   }
 469 | 
 470 |   // ADAPTER: OpenAI Compatible (Standard)
 471 |   const body: any = {
 472 |     model: provider.model,
 473 |     messages: messages,
 474 |   };
 475 |   if (tools) body.tools = tools;
 476 |   // If we have tools, we want to allow the caller to specify if it's mandatory
 477 |   if (tools) body.tool_choice = (tools.length > 0 && messages[0].content.includes('STRICT')) ? { type: "function", function: { name: tools[0].function.name } } : "auto";
 478 |   if (responseFormat) body.response_format = responseFormat;
 479 | 
 480 |   const res = await fetch(provider.baseUrl, {
 481 |     method: 'POST',
 482 |     headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
 483 |     body: JSON.stringify(body)
 484 |   });
 485 |   
 486 |   const data = await res.json();
 487 |   // AI Response Summary
 488 |   if (data.error) console.error(`[AI_ERR] Provider: ${provider.name}`, data.error);
 489 |   
 490 |   if (!res.ok || data.error) {
 491 |       const errMsg = data.error ? (data.error.message || JSON.stringify(data.error)) : `HTTP ${res.status} ${res.statusText}`;
 492 |       throw new Error(`Provider Error (${provider.name}): ${errMsg}`);
 493 |   }
 494 | 
 495 |   return {
 496 |     raw: data,
 497 |     content: data.choices?.[0]?.message?.content || "",
 498 |     tool_calls: data.choices?.[0]?.message?.tool_calls
 499 |   };
 500 | }
