 879 | 
 880 |   const createFingerprint = (str: string) => {
 881 |     let clean = "";
 882 |     const map: number[] = [];
 883 |     for (let i = 0; i < str.length; i++) {
 884 |       if (!/\s/.test(str[i])) {
 885 |         clean += str[i];
 886 |         map.push(i);
 887 |       }
 888 |     }
 889 |     return { clean, map };
 890 |   };
 891 | 
 892 |   const fileFP = createFingerprint(originalContent);
 893 |   const searchFP = createFingerprint(searchBlock);
