 895 |   // 1. Strict Structural Match
 896 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 897 | 
 898 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 899 |   if (matchIndex === -1) {
 900 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
